    cyan:   { ring: "ring-cyan-500/40",   bg: "bg-cyan-500/15",   text: "text-cyan-300",   border: "border-cyan-500/30" },
    violet: { ring: "ring-violet-500/40", bg: "bg-violet-500/15", text: "text-violet-300", border: "border-violet-500/30" },
    indigo: { ring: "ring-indigo-500/40", bg: "bg-indigo-500/15", text: "text-indigo-300", border: "border-indigo-500/30" },
    orange: { ring: "ring-orange-500/40", bg: "bg-orange-500/15", text: "text-orange-300", border: "border-orange-500/30" },
