    useEffect(() => {
      const params = new URLSearchParams(searchString);
      if (params.get("unlock_success") === "1") {
        const actorId = params.get("actor");
        const actor = actorId ? SIGNATURE_CAST.find(a => a.id === actorId) : null;
        setUnlockSuccess(actor?.name ?? "Actor");
        actorsQuery.refetch();
      }
    }, [searchString]);

    const userTier = (user as any)?.subscriptionTier ?? "none";
    const planAccess: string[] = PLAN_CAST_ACCESS[userTier] ?? [];

    function getEntitlementState(actor: Actor): "plan_included" | "unlocked" | "locked" {
      const serverActor = serverEntitlements.find((a: any) => a.id === actor.id);
      if (serverActor?.isEntitled) {
        return serverActor.entitlementSource === "paid_unlock" ? "unlocked" : "plan_included";
      }
      if (planAccess.includes(actor.tier)) return "plan_included";
      return "locked";
    }

    const filtered = SIGNATURE_CAST.filter((actor) => {
      const matchSearch =
        !search ||
        actor.name.toLowerCase().includes(search.toLowerCase()) ||
        actor.archetype.toLowerCase().includes(search.toLowerCase()) ||
        actor.hook.toLowerCase().includes(search.toLowerCase()) ||
        actor.nationality.toLowerCase().includes(search.toLowerCase());
      const matchCategory = category === "All" || actor.category === category;
      const matchGenre = genre === "All" || actor.genres.some((g: string) => g.toLowerCase().includes(genre.toLowerCase()));
      const matchTier = tierFilter === "All" || actor.tier === tierFilter;
      return matchSearch && matchCategory && matchGenre && matchTier;
    });

    const toggleShortlist = (id: string) =>
      setShortlist((prev) => prev.includes(id) ? prev.filter((a) => a !== id) : [...prev, id]);

    const handleCastNow = (actor: Actor) => {
      const state = getEntitlementState(actor);
      if (state === "locked") { setUnlockActor(actor); setSelectedLicense("creator"); }
      else navigate("/projects/new");
    };

    const handleUnlockCheckout = async () => {
      if (!unlockActor) return;
      if (!user) { navigate("/login"); return; }
      setIsCheckingOut(true);
      checkoutMutation.mutate({
        actorId: unlockActor.id,
        licenseType: selectedLicense,
      });
    };

    const accent = unlockActor ? getAccent(unlockActor.accentColor) : null;
    const selectedAccent = selectedActor ? getAccent(selectedActor.accentColor) : null;

